import os
import io
import json
import time
import pickle
import threading
from dataclasses import dataclass, asdict
from typing import Dict, List, Optional, Tuple

import numpy as np
from fastapi import FastAPI, File, UploadFile, HTTPException, Body
from fastapi.responses import JSONResponse
from pydantic import BaseModel, Field

try:
    import cv2
except Exception as e:
    raise RuntimeError("opencv-python is required") from e

try:
    import face_recognition
except Exception as e:
    raise RuntimeError("face_recognition is required (dlib dependency). Install face_recognition.") from e


# ---------------------------
# Config
# ---------------------------

MODEL_DIR = os.environ.get("FR_MODEL_DIR", "./fr_model")
EMPLOYEE_DIR = os.environ.get("FR_EMPLOYEE_DIR", "./employees")
MODEL_PATH = os.path.join(MODEL_DIR, "model.pkl")

DETECTION_MODEL = os.environ.get("FR_DETECTION_MODEL", "hog")  # "hog" or "cnn"
NUM_JITTERS = int(os.environ.get("FR_NUM_JITTERS", "1"))
UPSAMPLE_TIMES = int(os.environ.get("FR_UPSAMPLE_TIMES", "1"))
FACE_LOCATION_MODEL = os.environ.get("FR_FACE_LOCATION_MODEL", DETECTION_MODEL)

DEFAULT_TEMPERATURE = float(os.environ.get("FR_TEMPERATURE", "0.08"))
DEFAULT_MIN_FACE_SIZE = int(os.environ.get("FR_MIN_FACE_SIZE", "40"))

# Prevent providing guidance for wrongdoing:
# This API intentionally does not provide an "authorize/deny" endpoint or any bypass-adjacent utility.
# It returns distributions only; access decisions should be handled by a separate audited system.


# ---------------------------
# Helpers
# ---------------------------

def _ensure_dirs():
    os.makedirs(MODEL_DIR, exist_ok=True)
    os.makedirs(EMPLOYEE_DIR, exist_ok=True)


def _read_image_bytes(b: bytes) -> np.ndarray:
    arr = np.frombuffer(b, dtype=np.uint8)
    img_bgr = cv2.imdecode(arr, cv2.IMREAD_COLOR)
    if img_bgr is None:
        raise ValueError("Could not decode image")
    img_rgb = cv2.cvtColor(img_bgr, cv2.COLOR_BGR2RGB)
    return img_rgb


def _softmax(x: np.ndarray) -> np.ndarray:
    x = x - np.max(x)
    ex = np.exp(x)
    s = np.sum(ex)
    if s <= 0:
        return np.ones_like(x) / max(len(x), 1)
    return ex / s


def _is_image_file(fn: str) -> bool:
    ext = os.path.splitext(fn.lower())[1]
    return ext in {".jpg", ".jpeg", ".png", ".bmp", ".tif", ".tiff", ".webp"}


def _list_employee_classes(employee_dir: str) -> List[str]:
    if not os.path.isdir(employee_dir):
        return []
    classes = []
    for name in sorted(os.listdir(employee_dir)):
        p = os.path.join(employee_dir, name)
        if os.path.isdir(p) and not name.startswith("."):
            classes.append(name)
    return classes


def _iter_images_for_class(employee_dir: str, cls: str):
    base = os.path.join(employee_dir, cls)
    for root, _, files in os.walk(base):
        for f in sorted(files):
            if _is_image_file(f):
                yield os.path.join(root, f)


def _face_boxes(img_rgb: np.ndarray) -> List[Tuple[int, int, int, int]]:
    return face_recognition.face_locations(
        img_rgb,
        number_of_times_to_upsample=UPSAMPLE_TIMES,
        model=FACE_LOCATION_MODEL
    )


def _box_size(box: Tuple[int, int, int, int]) -> Tuple[int, int]:
    top, right, bottom, left = box
    return max(0, right - left), max(0, bottom - top)


def _compute_embeddings(img_rgb: np.ndarray, boxes: Optional[List[Tuple[int, int, int, int]]] = None) -> List[np.ndarray]:
    if boxes is None:
        boxes = _face_boxes(img_rgb)
    if not boxes:
        return []
    enc = face_recognition.face_encodings(img_rgb, known_face_locations=boxes, num_jitters=NUM_JITTERS, model="small")
    return [np.asarray(e, dtype=np.float32) for e in enc]


def _stable_hash_bytes(b: bytes) -> str:
    import hashlib
    return hashlib.sha256(b).hexdigest()


# ---------------------------
# Model definition
# ---------------------------

@dataclass
class FRModel:
    version: int
    created_at: float
    employee_dir: str
    detection_model: str
    num_jitters: int
    upsample_times: int
    classes: List[str]  # class labels
    class_centroids: np.ndarray  # shape (C, 128)
    class_counts: np.ndarray  # shape (C,)
    # Optional: store training embedding count for reference
    embedding_count: int

    def to_bytes(self) -> bytes:
        payload = {
            "version": self.version,
            "created_at": self.created_at,
            "employee_dir": self.employee_dir,
            "detection_model": self.detection_model,
            "num_jitters": self.num_jitters,
            "upsample_times": self.upsample_times,
            "classes": self.classes,
            "class_centroids": self.class_centroids.astype(np.float32),
            "class_counts": self.class_counts.astype(np.int32),
            "embedding_count": self.embedding_count,
        }
        return pickle.dumps(payload, protocol=pickle.HIGHEST_PROTOCOL)

    @staticmethod
    def from_bytes(b: bytes) -> "FRModel":
        payload = pickle.loads(b)
        return FRModel(
            version=int(payload["version"]),
            created_at=float(payload["created_at"]),
            employee_dir=str(payload["employee_dir"]),
            detection_model=str(payload["detection_model"]),
            num_jitters=int(payload["num_jitters"]),
            upsample_times=int(payload["upsample_times"]),
            classes=list(payload["classes"]),
            class_centroids=np.asarray(payload["class_centroids"], dtype=np.float32),
            class_counts=np.asarray(payload["class_counts"], dtype=np.int32),
            embedding_count=int(payload.get("embedding_count", 0)),
        )

    def predict_distribution(
        self,
        embedding: np.ndarray,
        temperature: float = DEFAULT_TEMPERATURE
    ) -> Dict[str, float]:
        if self.class_centroids.size == 0 or len(self.classes) == 0:
            return {}
        emb = np.asarray(embedding, dtype=np.float32).reshape(1, -1)
        cent = self.class_centroids  # (C, 128)
        d = np.linalg.norm(cent - emb, axis=1)  # (C,)
        t = max(float(temperature), 1e-6)
        logits = -d / t
        probs = _softmax(logits)
        return {self.classes[i]: float(probs[i]) for i in range(len(self.classes))}

    def distances(
        self,
        embedding: np.ndarray
    ) -> Dict[str, float]:
        if self.class_centroids.size == 0 or len(self.classes) == 0:
            return {}
        emb = np.asarray(embedding, dtype=np.float32).reshape(1, -1)
        d = np.linalg.norm(self.class_centroids - emb, axis=1)
        return {self.classes[i]: float(d[i]) for i in range(len(self.classes))}


# ---------------------------
# Training
# ---------------------------

@dataclass
class TrainStats:
    classes: int
    images_seen: int
    images_used: int
    faces_detected: int
    faces_used: int
    per_class_faces: Dict[str, int]
    skipped_images: List[Dict[str, str]]
    duration_ms: int


def train_from_directory(employee_dir: str) -> Tuple[FRModel, TrainStats]:
    t0 = time.time()
    _ensure_dirs()

    classes = _list_employee_classes(employee_dir)
    if not classes:
        raise ValueError(f"No class subfolders found in employee_dir: {employee_dir}")

    centroids = []
    counts = []
    embedding_count = 0

    images_seen = 0
    images_used = 0
    faces_detected = 0
    faces_used = 0
    per_class_faces: Dict[str, int] = {c: 0 for c in classes}
    skipped: List[Dict[str, str]] = []

    for cls in classes:
        cls_embs: List[np.ndarray] = []
        for path in _iter_images_for_class(employee_dir, cls):
            images_seen += 1
            try:
                img = face_recognition.load_image_file(path)
            except Exception:
                skipped.append({"path": path, "reason": "load_failed"})
                continue

            boxes = _face_boxes(img)
            if not boxes:
                skipped.append({"path": path, "reason": "no_face_detected"})
                continue

            # Filter very small faces to avoid noise
            filtered_boxes = []
            for b in boxes:
                w, h = _box_size(b)
                if min(w, h) >= DEFAULT_MIN_FACE_SIZE:
                    filtered_boxes.append(b)
            if not filtered_boxes:
                skipped.append({"path": path, "reason": "faces_too_small"})
                continue

            faces_detected += len(filtered_boxes)

            # Use the largest face in the image for training to reduce mislabels
            sizes = [(_box_size(b)[0] * _box_size(b)[1]) for b in filtered_boxes]
            largest_idx = int(np.argmax(sizes))
            box = [filtered_boxes[largest_idx]]

            embs = _compute_embeddings(img, box)
            if not embs:
                skipped.append({"path": path, "reason": "embedding_failed"})
                continue

            images_used += 1
            cls_embs.append(embs[0])
            faces_used += 1
            per_class_faces[cls] += 1
            embedding_count += 1

        if len(cls_embs) == 0:
            centroid = np.zeros((128,), dtype=np.float32)
            count = 0
        else:
            E = np.stack(cls_embs, axis=0).astype(np.float32)
            centroid = E.mean(axis=0)
            count = E.shape[0]

        centroids.append(centroid)
        counts.append(count)

    class_centroids = np.stack(centroids, axis=0).astype(np.float32)
    class_counts = np.asarray(counts, dtype=np.int32)

    model = FRModel(
        version=1,
        created_at=time.time(),
        employee_dir=employee_dir,
        detection_model=FACE_LOCATION_MODEL,
        num_jitters=NUM_JITTERS,
        upsample_times=UPSAMPLE_TIMES,
        classes=classes,
        class_centroids=class_centroids,
        class_counts=class_counts,
        embedding_count=embedding_count
    )

    stats = TrainStats(
        classes=len(classes),
        images_seen=images_seen,
        images_used=images_used,
        faces_detected=faces_detected,
        faces_used=faces_used,
        per_class_faces=per_class_faces,
        skipped_images=skipped[:5000],
        duration_ms=int((time.time() - t0) * 1000)
    )
    return model, stats


def save_model(model: FRModel, path: str = MODEL_PATH):
    _ensure_dirs()
    with open(path, "wb") as f:
        f.write(model.to_bytes())


def load_model(path: str = MODEL_PATH) -> Optional[FRModel]:
    if not os.path.exists(path):
        return None
    with open(path, "rb") as f:
        b = f.read()
    return FRModel.from_bytes(b)


# ---------------------------
# API
# ---------------------------

app = FastAPI(title="Facial Recognition Distribution API", version="1.0")

_model_lock = threading.Lock()
_model: Optional[FRModel] = None


class TrainRequest(BaseModel):
    employee_dir: str = Field(default=EMPLOYEE_DIR)
    save: bool = Field(default=True)


class PredictOptions(BaseModel):
    temperature: float = Field(default=DEFAULT_TEMPERATURE, ge=1e-6)
    include_distances: bool = Field(default=True)
    include_top_k: int = Field(default=0, ge=0)
    min_face_size: int = Field(default=DEFAULT_MIN_FACE_SIZE, ge=1)


def _get_model() -> FRModel:
    global _model
    with _model_lock:
        if _model is None:
            m = load_model(MODEL_PATH)
            if m is None:
                raise HTTPException(status_code=503, detail="Model not trained. Call /train first.")
            _model = m
        return _model


@app.get("/health")
def health():
    global _model
    m = None
    with _model_lock:
        m = _model
    if m is None and os.path.exists(MODEL_PATH):
        try:
            m = load_model(MODEL_PATH)
        except Exception:
            m = None
    return {
        "ok": True,
        "model_loaded": m is not None,
        "model_path": MODEL_PATH,
        "employee_dir": EMPLOYEE_DIR,
        "detection_model": FACE_LOCATION_MODEL,
        "num_jitters": NUM_JITTERS,
        "upsample_times": UPSAMPLE_TIMES,
    }


@app.post("/train")
def train(req: TrainRequest = Body(default=TrainRequest())):
    global _model
    try:
        model, stats = train_from_directory(req.employee_dir)
    except Exception as e:
        raise HTTPException(status_code=400, detail=str(e))

    if req.save:
        try:
            save_model(model, MODEL_PATH)
        except Exception as e:
            raise HTTPException(status_code=500, detail=f"Failed to save model: {e}")

    with _model_lock:
        _model = model

    return {
        "model": {
            "version": model.version,
            "created_at": model.created_at,
            "employee_dir": model.employee_dir,
            "classes": model.classes,
            "class_counts": model.class_counts.tolist(),
            "embedding_count": model.embedding_count,
        },
        "stats": asdict(stats),
        "saved_to": MODEL_PATH if req.save else None,
    }


@app.get("/model")
def model_info():
    m = _get_model()
    return {
        "version": m.version,
        "created_at": m.created_at,
        "employee_dir": m.employee_dir,
        "detection_model": m.detection_model,
        "num_jitters": m.num_jitters,
        "upsample_times": m.upsample_times,
        "classes": m.classes,
        "class_counts": m.class_counts.tolist(),
        "embedding_count": m.embedding_count,
    }


@app.post("/predict")
async def predict(
    file: UploadFile = File(...),
    options_json: str = Body(default="{}")
):
    m = _get_model()

    try:
        options_dict = json.loads(options_json) if options_json else {}
        options = PredictOptions(**options_dict)
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Invalid options_json: {e}")

    content = await file.read()
    if not content:
        raise HTTPException(status_code=400, detail="Empty file")

    try:
        img_rgb = _read_image_bytes(content)
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Invalid image: {e}")

    # detect faces
    boxes = _face_boxes(img_rgb)
    if not boxes:
        return JSONResponse(
            status_code=200,
            content={
                "faces": [],
                "warning": "no_face_detected",
                "classes": m.classes,
            },
        )

    # filter by size
    filtered = []
    for b in boxes:
        w, h = _box_size(b)
        if min(w, h) >= options.min_face_size:
            filtered.append(b)
    if not filtered:
        return JSONResponse(
            status_code=200,
            content={
                "faces": [],
                "warning": "faces_too_small",
                "classes": m.classes,
            },
        )

    embs = _compute_embeddings(img_rgb, filtered)
    if not embs:
        raise HTTPException(status_code=500, detail="Failed to compute embeddings")

    faces_out = []
    for idx, (box, emb) in enumerate(zip(filtered, embs)):
        dist = m.predict_distribution(emb, temperature=options.temperature)
        distances = m.distances(emb) if options.include_distances else None

        # Ensure full distribution includes all classes in order
        probs_vec = [dist.get(c, 0.0) for c in m.classes]

        top_k = int(options.include_top_k or 0)
        top = None
        if top_k > 0:
            pairs = list(zip(m.classes, probs_vec))
            pairs.sort(key=lambda x: x[1], reverse=True)
            top = [{"class": c, "probability": float(p)} for c, p in pairs[:top_k]]

        top_class = None
        top_prob = None
        if len(probs_vec) > 0:
            i = int(np.argmax(np.asarray(probs_vec, dtype=np.float32)))
            top_class = m.classes[i]
            top_prob = float(probs_vec[i])

        faces_out.append(
            {
                "face_index": idx,
                "box": {"top": int(box[0]), "right": int(box[1]), "bottom": int(box[2]), "left": int(box[3])},
                "distribution": {m.classes[i]: float(probs_vec[i]) for i in range(len(m.classes))},
                "top": {"class": top_class, "probability": top_prob},
                "top_k": top,
                "distances": distances,
            }
        )

    return {
        "file": {"filename": file.filename, "content_type": file.content_type, "sha256": _stable_hash_bytes(content)},
        "classes": m.classes,
        "faces": faces_out,
        "options_used": options.model_dump(),
        "model": {"created_at": m.created_at, "employee_dir": m.employee_dir},
    }


@app.post("/reload")
def reload_model():
    global _model
    try:
        m = load_model(MODEL_PATH)
        if m is None:
            raise HTTPException(status_code=404, detail="No saved model found")
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Failed to load model: {e}")

    with _model_lock:
        _model = m
    return {"ok": True, "model_loaded": True, "created_at": m.created_at, "classes": m.classes}


